/* ============= DEVICE IMAGE ============= */
const DEVICE_IMG = 'data:image/jpeg;base64,';

document.querySelectorAll('.device-img').forEach(img => img.src = DEVICE_IMG);

/* ============= HAMBURGER ============= */
const burger = document.getElementById('navBurger');
const mobileMenu = document.getElementById('mobileMenu');
const overlay = document.getElementById('overlay');

function openMobileMenu() {
  mobileMenu.classList.add('open');
  burger.classList.add('open');
  overlay.classList.add('active');
}
function closeMobileMenu() {
  mobileMenu.classList.remove('open');
  burger.classList.remove('open');
  const cd = document.getElementById('cartDrawer');
  const am = document.getElementById('authModal');
  if ((!cd || !cd.classList.contains('open')) && (!am || !am.classList.contains('open'))) {
    overlay.classList.remove('active');
  }
}
if (burger) burger.addEventListener('click', () => {
  mobileMenu.classList.contains('open') ? closeMobileMenu() : openMobileMenu();
});
if (overlay) overlay.addEventListener('click', () => {
  closeMobileMenu(); closeCart(); closeAuth();
});
document.querySelectorAll('[data-mm]').forEach(a => {
  a.addEventListener('click', () => closeMobileMenu());
});
const mmSignin = document.getElementById('mmSignin');
if (mmSignin) mmSignin.addEventListener('click', () => { closeMobileMenu(); openAuth('signin'); });
const mmCart = document.getElementById('mmCart');
if (mmCart) mmCart.addEventListener('click', () => { closeMobileMenu(); setTimeout(openCart, 200); });

/* ============= AUTH MODAL ============= */
const authModal = document.getElementById('authModal');
function openAuth(mode) {
  if (!authModal) return;
  switchAuth(mode || 'signin');
  authModal.classList.add('open');
  overlay.classList.add('active');
}
function closeAuth() { if (authModal) authModal.classList.remove('open'); }
function switchAuth(mode) {
  document.querySelectorAll('.auth-tab').forEach(t => t.classList.toggle('active', t.dataset.authTab === mode));
  const title = document.getElementById('authTitle');
  const sub = document.getElementById('authSub');
  const btn = document.getElementById('authSubmitBtn');
  const alt = document.getElementById('authAltText');
  const link = document.getElementById('authAltLink');
  const nf = document.getElementById('nameField');
  if (mode === 'signup') {
    if (title) title.textContent = 'Create your account.';
    if (sub) sub.textContent = 'Pair your CLIMAS device after preordering.';
    if (btn) btn.textContent = 'Create account';
    if (nf) nf.style.display = 'block';
    if (alt) alt.textContent = 'Already have an account? ';
    if (link) link.textContent = 'Sign in';
  } else {
    if (title) title.textContent = 'Welcome back.';
    if (sub) sub.textContent = 'Sign in to choose a plan and activate your device.';
    if (btn) btn.textContent = 'Sign in';
    if (nf) nf.style.display = 'none';
    if (alt) alt.textContent = 'New to CLIMAS? ';
    if (link) link.textContent = 'Create an account';
  }
}
document.querySelectorAll('.auth-tab').forEach(t => t.addEventListener('click', () => switchAuth(t.dataset.authTab)));
const authAltLink = document.getElementById('authAltLink');
if (authAltLink) authAltLink.addEventListener('click', () => {
  const cur = document.querySelector('.auth-tab.active');
  switchAuth(cur && cur.dataset.authTab === 'signin' ? 'signup' : 'signin');
});
const authOpenBtn = document.getElementById('authOpenBtn');
if (authOpenBtn) authOpenBtn.addEventListener('click', () => openAuth('signin'));
document.querySelectorAll('[data-open-auth]').forEach(el => {
  el.addEventListener('click', e => { e.preventDefault(); openAuth(el.dataset.openAuth || 'signin'); });
});
const authSubmitBtn = document.getElementById('authSubmitBtn');
if (authSubmitBtn) authSubmitBtn.addEventListener('click', () => {
  const nameVal = (document.getElementById('nameInput') || {}).value || '';
  const emailVal = (document.getElementById('emailInput') || {}).value || '';
  let userName = 'User';
  if (nameVal.trim()) userName = nameVal.trim().split(' ')[0];
  else if (emailVal.trim()) userName = emailVal.trim().split('@')[0].split('.')[0].replace(/^\w/, c => c.toUpperCase());
  sessionStorage.setItem('climas_user', userName);
  sessionStorage.setItem('climas_signedin', '1');
  if (authOpenBtn) authOpenBtn.textContent = userName;
  closeAuth();
  overlay.classList.remove('active');
  // redirect to preorder
  window.location.href = 'preorder.html';
});

/* ============= CART ============= */
const PLANS = {
  basic: { name: 'Basic', price: 18, tag: 'Device only · No online dashboard', dashboard: false },
  pro:   { name: 'Pro',   price: 28, tag: 'Full portal · Live dashboard',      dashboard: true  }
};
function getCart() { try { return JSON.parse(sessionStorage.getItem('climas_cart') || '[]'); } catch(e) { return []; } }
function setCart(c) { sessionStorage.setItem('climas_cart', JSON.stringify(c)); }

const cartDrawer = document.getElementById('cartDrawer');
function openCart() { if (cartDrawer) { cartDrawer.classList.add('open'); overlay.classList.add('active'); } }
function closeCart() { if (cartDrawer) cartDrawer.classList.remove('open'); }
const cartOpenBtn = document.getElementById('cartOpenBtn');
if (cartOpenBtn) cartOpenBtn.addEventListener('click', openCart);
const cartCloseBtn = document.getElementById('cartCloseBtn');
if (cartCloseBtn) cartCloseBtn.addEventListener('click', () => { closeCart(); overlay.classList.remove('active'); });

function renderCart() {
  const cart = getCart();
  const body = document.getElementById('cartBody');
  const footer = document.getElementById('cartFooter');
  const count = document.getElementById('cartCount');
  const mmCount = document.getElementById('mmCartCount');
  if (!body) return;
  if (cart.length === 0) {
    body.innerHTML = '<div class="cart-empty"><svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"/><path d="M3 6h18"/><path d="M16 10a4 4 0 0 1-8 0"/></svg><h4>Your cart is empty</h4><p style="font-size:13px;margin-bottom:20px">Add a CLIMAS device with a plan to get started.</p><a class="btn-primary" href="preorder.html">Go to preorder</a></div>';
    if (footer) footer.style.display = 'none';
    if (count) { count.textContent = '0'; count.classList.add('empty'); }
    if (mmCount) mmCount.textContent = '0';
  } else {
    body.innerHTML = cart.map((item, i) => `<div class="cart-item"><div class="cart-item-thumb"><img src="${DEVICE_IMG}" alt="CLIMAS" /></div><div><div class="cart-item-name">CLIMAS</div><div class="cart-item-sub">${PLANS[item.plan].name.toUpperCase()}</div><div class="cart-item-sub" style="margin-top:4px;color:var(--safe)">Device · Free</div><a class="cart-item-remove" data-remove="${i}">Remove</a></div><div><div class="cart-item-price">₵${PLANS[item.plan].price}</div><div class="cart-item-sub" style="text-align:right">/ month</div></div></div>`).join('');
    if (footer) footer.style.display = 'block';
    const total = cart.reduce((s, it) => s + PLANS[it.plan].price, 0);
    const sub = document.getElementById('cartSubtotal');
    if (sub) sub.textContent = '₵' + total.toFixed(2);
    if (count) { count.textContent = cart.length; count.classList.remove('empty'); }
    if (mmCount) mmCount.textContent = cart.length;
    body.querySelectorAll('[data-remove]').forEach(el => {
      el.addEventListener('click', () => { const c = getCart(); c.splice(+el.dataset.remove, 1); setCart(c); renderCart(); });
    });
  }
}
renderCart();

// add to cart
const addBtn = document.getElementById('addToCartBtn');
if (addBtn) addBtn.addEventListener('click', () => {
  const sel = document.querySelector('.plan-option.selected');
  const plan = sel ? sel.dataset.plan : 'pro';
  setCart([{ plan }]);
  renderCart();
  openCart();
});

// checkout btn
const checkoutBtn = document.getElementById('checkoutBtn');
if (checkoutBtn) checkoutBtn.addEventListener('click', () => {
  const signedIn = sessionStorage.getItem('climas_signedin');
  if (!signedIn) { closeCart(); overlay.classList.remove('active'); openAuth('signin'); return; }
  closeCart(); overlay.classList.remove('active');
  // show checkout section
  const cs = document.getElementById('checkoutSection');
  const ss = document.getElementById('storeSection');
  if (cs && ss) { ss.style.display = 'none'; cs.style.display = 'block'; }
  renderCheckoutSummary();
  window.scrollTo({ top: 0, behavior: 'instant' });
});

function renderCheckoutSummary() {
  const cart = getCart();
  if (cart.length === 0) return;
  const plan = PLANS[cart[0].plan];
  const si = document.getElementById('summaryItems');
  if (si) si.innerHTML = `<div class="summary-row"><span>Plan · <strong>${plan.name}</strong></span><span>₵${plan.price}/mo</span></div>`;
  const st = document.getElementById('summaryTotal');
  if (st) st.textContent = '₵' + plan.price;
}

// place order
const placeOrderBtn = document.getElementById('placeOrderBtn');
if (placeOrderBtn) placeOrderBtn.addEventListener('click', () => {
  const cart = getCart();
  if (cart.length === 0) return;
  const plan = cart[0].plan;
  sessionStorage.setItem('climas_plan', plan);
  sessionStorage.setItem('climas_subscribed', '1');
  setCart([]);
  renderCart();
  const cs = document.getElementById('checkoutSection');
  const sv = document.getElementById('successSection');
  if (cs) cs.style.display = 'none';
  if (sv) sv.style.display = 'block';
  // hide dashboard button for basic
  const dashBtn = document.getElementById('successDashBtn');
  if (dashBtn) dashBtn.style.display = PLANS[plan].dashboard ? '' : 'none';
  window.scrollTo({ top: 0, behavior: 'instant' });
});

/* ============= PLAN SELECTOR ============= */
document.querySelectorAll('.plan-option').forEach(opt => {
  opt.addEventListener('click', () => {
    document.querySelectorAll('.plan-option').forEach(o => o.classList.remove('selected'));
    opt.classList.add('selected');
  });
});

/* ============= FAQ ============= */
document.querySelectorAll('.faq-item').forEach(item => {
  item.querySelector('.faq-q')?.addEventListener('click', () => {
    document.querySelectorAll('.faq-item').forEach(i => { if (i !== item) i.classList.remove('open'); });
    item.classList.toggle('open');
  });
});

/* ============= CONTACT FORM ============= */
const contactSendBtn = document.getElementById('contactSendBtn');
if (contactSendBtn) contactSendBtn.addEventListener('click', () => {
  const name = (document.getElementById('contactName') || {}).value || '';
  const email = (document.getElementById('contactEmail') || {}).value || '';
  const msg = (document.getElementById('contactMessage') || {}).value || '';
  const sent = document.getElementById('contactSent');
  if (!name.trim() || !email.trim() || !msg.trim()) {
    if (sent) { sent.textContent = '⚠ Please fill in your name, email, and message.'; sent.style.color = 'var(--danger)'; sent.classList.add('visible'); }
    return;
  }
  if (sent) { sent.textContent = '✓ Message sent. We\'ll reply within 24 hours.'; sent.style.color = 'var(--safe)'; sent.classList.add('visible'); }
  ['contactName','contactEmail','contactSubject','contactMessage'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  setTimeout(() => { if (sent) sent.classList.remove('visible'); }, 5000);
});

/* ============= ON LOAD: RESTORE AUTH STATE ============= */
(function() {
  const user = sessionStorage.getItem('climas_user');
  if (user && authOpenBtn) authOpenBtn.textContent = user;
})();

/* ============= DASHBOARD LIVE SIMULATION ============= */
if (document.getElementById('view-dashboard')) {
  let t = 26.4, h = 58, g = 112;
  const hist = { T: [], H: [], G: [] };
  for (let i = 0; i < 48; i++) {
    hist.T.push(25 + Math.sin(i/6)*2 + (Math.random()-0.5)*0.6);
    hist.H.push(55 + Math.cos(i/8)*8 + (Math.random()-0.5)*2);
    hist.G.push(90 + Math.sin(i/5)*30 + (Math.random()-0.5)*15);
  }
  function drawSpark(id, data, color) {
    const svg = document.getElementById(id);
    if (!svg) return;
    const min = Math.min(...data), max = Math.max(...data), range = max - min || 1;
    const pts = data.map((v,i) => `${(i/(data.length-1))*200},${40 - ((v-min)/range)*38}`).join(' ');
    svg.innerHTML = `<polyline points="${pts}" fill="none" stroke="${color}" stroke-width="2" vector-effect="non-scaling-stroke"/>`;
  }
  function updateLive() {
    t += (Math.random()-0.5)*0.3; h += (Math.random()-0.5)*0.8; g += (Math.random()-0.5)*8;
    t = Math.max(23, Math.min(32, t)); h = Math.max(40, Math.min(75, h)); g = Math.max(50, Math.min(300, g));
    hist.T.push(t); hist.H.push(h); hist.G.push(g);
    if (hist.T.length > 48) { hist.T.shift(); hist.H.shift(); hist.G.shift(); }
    const mT = document.getElementById('mT'); if (mT) mT.textContent = t.toFixed(1);
    const mH = document.getElementById('mH'); if (mH) mH.textContent = h.toFixed(0);
    const mG = document.getElementById('mG'); if (mG) mG.textContent = g.toFixed(0);
    drawSpark('sparkT', hist.T.slice(-20), '#c0431c');
    drawSpark('sparkH', hist.H.slice(-20), '#1a3b2d');
    drawSpark('sparkG', hist.G.slice(-20), '#d9a441');
    // big chart
    const chart = document.getElementById('mainChart');
    if (chart) {
      const W = 700, H = 200;
      const drawLine = (arr, color) => {
        const min = Math.min(...arr), max = Math.max(...arr), range = max - min || 1;
        return arr.map((v,i) => `${(i/(arr.length-1))*W},${H - ((v-min)/range)*(H-20) - 10}`).join(' ');
      };
      chart.innerHTML = `
        <polyline points="${drawLine(hist.T,'')}" fill="none" stroke="#c0431c" stroke-width="2" opacity=".8"/>
        <polyline points="${drawLine(hist.H,'')}" fill="none" stroke="#1a3b2d" stroke-width="2" opacity=".8"/>
        <polyline points="${drawLine(hist.G,'')}" fill="none" stroke="#d9a441" stroke-width="2" opacity=".6"/>
        <text x="10" y="16" fill="#c0431c" font-size="10" font-family="JetBrains Mono">TEMP</text>
        <text x="60" y="16" fill="#1a3b2d" font-size="10" font-family="JetBrains Mono">HUMIDITY</text>
        <text x="140" y="16" fill="#d9a441" font-size="10" font-family="JetBrains Mono">GAS</text>
        <text x="0" y="${H}" fill="#8a897e" font-size="9" font-family="JetBrains Mono">-24h</text>
        <text x="${W-30}" y="${H}" fill="#8a897e" font-size="9" font-family="JetBrains Mono">NOW</text>`;
    }
  }
  updateLive();
  setInterval(updateLive, 2000);

  // set user name on dashboard
  const user = sessionStorage.getItem('climas_user') || 'Phil';
  const dn = document.getElementById('dashName');
  if (dn) dn.textContent = user;
  // set plan info
  const plan = sessionStorage.getItem('climas_plan') || 'pro';
  const p = PLANS[plan];
  const dpn = document.getElementById('dashPlanName'); if (dpn) dpn.textContent = p.name;
  const dpt = document.getElementById('dashPlanTag'); if (dpt) dpt.textContent = p.tag;
  const dpp = document.getElementById('dashPlanPrice'); if (dpp) dpp.textContent = '₵' + p.price + ' / month';

  // Dashboard gate: redirect if not subscribed pro
  const subscribed = sessionStorage.getItem('climas_subscribed');
  if (!subscribed || plan !== 'pro') {
    document.getElementById('view-dashboard').innerHTML = '<div style="max-width:600px;margin:120px auto;text-align:center;padding:40px"><h2 style="font-family:Fraunces,serif;margin-bottom:16px">Dashboard requires a <em style="font-style:italic;color:var(--forest)">Pro</em> subscription.</h2><p style="color:var(--ink-soft);margin-bottom:28px">The live online dashboard is only available on the Pro plan (₵28/month). Upgrade or subscribe to access your readings, charts, and alert history.</p><a class="btn-hero" href="preorder.html">Get Pro →</a></div>';
  }
}
